// AWS Developer Associate (DVA-C02) - 100 Questions
const DVA_QUESTIONS = [
{id:'dva1',exams:['dva'],domain:'Development with AWS Services',text:'A developer needs to store environment-specific configuration for a Lambda function without hardcoding values. What is the best approach?',options:['Hardcode values in the function code','Use Lambda environment variables','Store in a separate S3 file','Use EC2 instance metadata'],correct:1,explanation:'Lambda environment variables allow you to dynamically configure your function without changing code, different per environment.'},
{id:'dva2',exams:['dva'],domain:'Development with AWS Services',text:'What is the maximum execution timeout for an AWS Lambda function?',options:['5 minutes','15 minutes','30 minutes','1 hour'],correct:1,explanation:'AWS Lambda functions can run for a maximum of 15 minutes (900 seconds). For longer tasks, use Step Functions or other services.'},
{id:'dva3',exams:['dva'],domain:'Security',text:'A developer needs their application to access AWS services without hardcoding credentials. What should they use when running on EC2?',options:['Store credentials in a .env file','Attach an IAM Role to the EC2 instance','Use the root account credentials','Store credentials in S3'],correct:1,explanation:'IAM Roles for EC2 provide temporary credentials through the instance metadata service. The SDK automatically retrieves them without any code changes.'},
{id:'dva4',exams:['dva'],domain:'Deployment',text:'What is a CloudFormation Stack?',options:['A physical stack of servers','A collection of AWS resources defined by a CloudFormation template, managed as a single unit','A stack trace for CloudFormation errors','A layer in a Lambda deployment package'],correct:1,explanation:'A CloudFormation Stack is the collection of AWS resources created from a template, allowing you to create, update, and delete related resources as a unit.'},
{id:'dva5',exams:['dva'],domain:'Development with AWS Services',text:'Which AWS SDK credential provider is checked first in the default credential provider chain?',options:['Environment variables','IAM Role for the instance','AWS credentials file','IAM Role for the task'],correct:0,explanation:'The AWS SDK checks credentials in this order: 1) Environment variables, 2) AWS credentials file, 3) AWS config file, 4) Container credentials (ECS), 5) Instance profile (EC2).'},
{id:'dva6',exams:['dva'],domain:'Deployment',text:'What does a CodeDeploy AppSpec file define?',options:['A list of servers to deploy to','The deployment lifecycle hooks and files to deploy for each target type (EC2, Lambda, ECS)','A CloudFormation template','The CI/CD pipeline configuration'],correct:1,explanation:'The AppSpec file defines the deployment actions: where to copy files on EC2/on-prem, or what Lambda function version/alias to deploy, plus lifecycle event hooks.'},
{id:'dva7',exams:['dva'],domain:'Development with AWS Services',text:'What is the DynamoDB single-table design pattern?',options:['Storing all data in one column','Storing all entities in one table using composite keys and secondary indexes to support multiple access patterns','Using one table per microservice','Storing only one item type per table'],correct:1,explanation:'Single-table design stores heterogeneous items in one table using partition and sort key combinations to support all access patterns efficiently at scale.'},
{id:'dva8',exams:['dva'],domain:'Security',text:'What is AWS Cognito Hosted UI?',options:['A UI component library','A pre-built, customizable web interface for user sign-up and sign-in that can be integrated into any app','A hosting service for React apps','A Cognito management console'],correct:1,explanation:'The Cognito Hosted UI is a pre-built, OAuth 2.0-compliant sign-in/sign-up web page that integrates with User Pools without building your own auth UI.'},
{id:'dva9',exams:['dva'],domain:'Deployment',text:'What is AWS CodeArtifact?',options:['A physical artifact storage service','A fully managed artifact repository for software packages (npm, Maven, PyPI, NuGet) that integrates with CI/CD pipelines','A code review artifact','An artifact for CloudFormation stacks'],correct:1,explanation:'CodeArtifact is a managed package repository that stores and retrieves software packages, integrating with build tools like Maven, Gradle, npm, and pip.'},
{id:'dva10',exams:['dva'],domain:'Development with AWS Services',text:'How do you handle DynamoDB conditional writes?',options:['Using SQL WHERE clauses','Using ConditionExpression in PutItem, UpdateItem, or DeleteItem to specify a condition that must be true for the write to succeed','Using transactions only','Using a lock mechanism'],correct:1,explanation:'ConditionExpressions enable optimistic locking—the write only succeeds if the condition is true (e.g., attribute_not_exists(pk) prevents overwriting existing items).'},
{id:'dva11',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is Amazon X-Ray used for?',options:['X-raying server hardware for defects','End-to-end distributed tracing of requests through your application, identifying performance bottlenecks and errors','A security penetration testing service','A monitoring service for physical infrastructure'],correct:1,explanation:'X-Ray traces requests as they travel through distributed components, providing a service map and flame graph to identify latency bottlenecks.'},
{id:'dva12',exams:['dva'],domain:'Development with AWS Services',text:'What is API Gateway caching?',options:['Caching API Gateway configuration','Caching API responses for a specified TTL to reduce calls to your backend and improve response times','Caching API keys for authentication','A content delivery cache'],correct:1,explanation:'API Gateway caching stores endpoint responses in a dedicated cache for a configurable TTL (up to 1 hour), reducing backend load and latency.'},
{id:'dva13',exams:['dva'],domain:'Security',text:'What is Cross-Origin Resource Sharing (CORS) in API Gateway?',options:['A cross-region data replication feature','A browser security feature requiring servers to explicitly allow cross-origin requests; must be configured in API Gateway for browser clients','A cross-account API sharing feature','A load balancing mechanism'],correct:1,explanation:'CORS allows browser-based applications to call APIs on different domains. API Gateway must return appropriate CORS headers (Access-Control-Allow-Origin) for browser clients.'},
{id:'dva14',exams:['dva'],domain:'Deployment',text:'What is a CloudFormation Change Set?',options:['A set of changes to your IAM policies','A preview of the changes CloudFormation will make to your stack before executing the update','A log of all changes to CloudFormation templates','A feature for rolling back stacks'],correct:1,explanation:'A Change Set summarizes proposed changes to a stack (resource additions, modifications, deletions) before you execute them, preventing unexpected changes.'},
{id:'dva15',exams:['dva'],domain:'Development with AWS Services',text:'What is the maximum size for an SQS message?',options:['64 KB','256 KB','1 MB','10 MB'],correct:1,explanation:'SQS messages can be up to 256 KB. For larger payloads, use the Extended Client Library to store the body in S3 and send a reference in SQS.'},
{id:'dva16',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is a CloudWatch Metric Filter?',options:['A filter on CloudWatch dashboards','Searches log data for specific terms and converts them to CloudWatch metrics, enabling alarms on log content','A way to filter out noisy logs','A CloudWatch pricing filter'],correct:1,explanation:'Metric filters scan log events for patterns (like error counts) and emit custom CloudWatch metrics, enabling alarms based on log content.'},
{id:'dva17',exams:['dva'],domain:'Development with AWS Services',text:'What is Lambda Layers?',options:['Lambda performance layers','A distribution mechanism to include libraries, custom runtimes, or configuration in Lambda functions without including them in the deployment package','Network layers for Lambda VPC access','Lambda execution layers for different runtimes'],correct:1,explanation:'Lambda Layers allow sharing common code (libraries, SDKs, config) across multiple functions, reducing package size and enabling centralized updates.'},
{id:'dva18',exams:['dva'],domain:'Security',text:'How do you implement fine-grained access control in DynamoDB for a multi-tenant application?',options:['Create separate tables per tenant','Use IAM policies with condition keys to restrict access to specific DynamoDB items by tenant ID','Use DynamoDB encryption per tenant','Use VPC endpoints per tenant'],correct:1,explanation:'IAM condition keys like dynamodb:LeadingKeys restrict users to only access DynamoDB items where the partition key matches their user ID—enabling multi-tenancy.'},
{id:'dva19',exams:['dva'],domain:'Deployment',text:'What is an Elastic Beanstalk .ebextensions?',options:['A file extension for Elastic Beanstalk apps','Configuration files in YAML/JSON format placed in a .ebextensions/ directory to customize and configure the Elastic Beanstalk environment','Extension settings for Elastic Beanstalk','Error extensions for debugging'],correct:1,explanation:'.ebextensions allow advanced environment configuration: installing packages, running commands, configuring OS settings, and creating AWS resources during deployment.'},
{id:'dva20',exams:['dva'],domain:'Development with AWS Services',text:'What is the AWS SDK Exponential Backoff?',options:['A power-saving mode for AWS SDKs','A retry strategy where each retry waits an exponentially increasing amount of time with jitter to avoid overwhelming throttled services','A gradual SDK version upgrade path','A backup strategy for SDK configurations'],correct:1,explanation:'Exponential backoff retries failed API calls with increasing delays (1s, 2s, 4s...) plus random jitter, preventing thundering herd on throttled services.'},
{id:'dva21',exams:['dva'],domain:'Development with AWS Services',text:'What is DynamoDB Global Secondary Index (GSI)?',options:['A global DNS index for DynamoDB','An index with a different partition and/or sort key than the base table, allowing queries on non-primary key attributes','A secondary backup of the primary index','A cross-region replication index'],correct:1,explanation:'A GSI has its own partition key and optional sort key, enabling efficient queries on attributes that are not the table primary key.'},
{id:'dva22',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'How do you trace Lambda function cold starts?',options:['Cold starts cannot be traced','Use X-Ray traces which show initialization time separately from function execution time','Use CloudTrail logs','Use CloudWatch Logs only'],correct:1,explanation:'X-Ray traces show the initialization segment (cold start) separately from the invocation segment, allowing you to measure and identify cold start impact.'},
{id:'dva23',exams:['dva'],domain:'Security',text:'What is API Gateway Lambda Authorizer?',options:['An IAM role for API Gateway','A Lambda function that controls access to your API by validating tokens or request parameters and returning an IAM policy','A built-in authentication mechanism','An API key validation service'],correct:1,explanation:'A Lambda Authorizer (custom authorizer) validates bearer tokens (JWT, OAuth) or request parameters and returns an IAM policy allowing or denying access.'},
{id:'dva24',exams:['dva'],domain:'Deployment',text:'What is the purpose of CodePipeline stages?',options:['Stages are performance levels of a pipeline','Pipeline stages (Source, Build, Test, Deploy) separate the workflow into logical phases, each containing one or more actions','Stages are environments (dev, staging, prod)','Stages control pipeline access permissions'],correct:1,explanation:'CodePipeline stages organize the workflow into sequential phases. Each stage has actions that must complete before the next stage begins.'},
{id:'dva25',exams:['dva'],domain:'Development with AWS Services',text:'What is S3 Multipart Upload and when should you use it?',options:['Uploading to multiple S3 buckets simultaneously','Uploading large objects in parts, recommended for objects over 100 MB, required for objects over 5 GB, and enables parallel/resumable uploads','Uploading files from multiple users','A method for uploading multiple file types'],correct:1,explanation:'Multipart Upload splits large files into parts (5MB-5GB each), uploads them in parallel, and assembles them. Required for objects > 5GB, recommended > 100MB.'},
{id:'dva26',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is CloudWatch Embedded Metrics Format (EMF)?',options:['A file format for CloudWatch dashboards','A specification for embedding CloudWatch metrics in structured log events, enabling custom metrics without extra API calls','An encrypted metrics format','A metric format for embedded systems'],correct:1,explanation:'EMF allows you to create custom metrics by embedding them in structured log events (JSON), eliminating the need for separate PutMetricData API calls.'},
{id:'dva27',exams:['dva'],domain:'Security',text:'What is server-side encryption with customer-provided keys (SSE-C) in S3?',options:['AWS manages the encryption keys','You provide the encryption key with each request; AWS performs encryption/decryption but does not store your key','AWS and customer share key management','S3 encrypts only selected objects'],correct:1,explanation:'With SSE-C, you manage encryption keys and send them with each request. AWS performs the crypto operations but never stores your key.'},
{id:'dva28',exams:['dva'],domain:'Deployment',text:'What is AWS CodeBuild buildspec.yml?',options:['A build specification for physical servers','A YAML file that defines the build commands, phases (install, pre_build, build, post_build), environment variables, and artifacts for CodeBuild','A CloudFormation resource specification','A build cost specification file'],correct:1,explanation:'buildspec.yml defines the build steps, runtime environment, commands, and output artifacts for CodeBuild, placed in the root of your source code.'},
{id:'dva29',exams:['dva'],domain:'Development with AWS Services',text:'What is the difference between SQS short polling and long polling?',options:['Short polling is more reliable','Short polling queries a subset of servers and may return empty; long polling waits (up to 20s) querying all servers, reducing empty responses and cost','Long polling is deprecated','They are identical in behavior'],correct:1,explanation:'Long polling (WaitTimeSeconds up to 20s) eliminates empty responses by waiting for messages, reducing API calls and cost compared to short polling.'},
{id:'dva30',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is CloudWatch Contributor Insights?',options:['Insights about CloudWatch contributors','Analyzes log data to identify the top contributors to application performance issues (e.g., top error-producing IPs, customers with most requests)','A developer contribution tracking tool','Insights about who modifies CloudWatch dashboards'],correct:1,explanation:'Contributor Insights uses rules to analyze log data and find the top-N contributors (IPs, URLs, users) to a metric, helping diagnose performance issues.'},
{id:'dva31',exams:['dva'],domain:'Development with AWS Services',text:'What is the purpose of an SQS FIFO queue Content-Based Deduplication?',options:['Comparing message content for quality','Using a SHA-256 hash of the message body to automatically assign deduplication IDs, preventing duplicates without custom dedup IDs','A feature for removing offensive content','Deduplicating S3 objects from SQS'],correct:1,explanation:'Content-based deduplication hashes the message body to create a deduplication ID automatically, so you do not need to provide a MessageDeduplicationId.'},
{id:'dva32',exams:['dva'],domain:'Security',text:'What is the AWS SDK default behavior when an API call fails due to a throttling error?',options:['Immediately raise an exception','Automatically retry with exponential backoff and jitter','Return null without retrying','Log the error and continue'],correct:1,explanation:'AWS SDKs automatically retry throttled requests (HTTP 429) with exponential backoff and jitter, with configurable retry counts per SDK.'},
{id:'dva33',exams:['dva'],domain:'Deployment',text:'What is a SAM (Serverless Application Model) template?',options:['A database schema for serverless apps','An extension of CloudFormation with simplified syntax for defining Lambda functions, API Gateway APIs, DynamoDB tables, and other serverless resources','A SAP integration module','A sample application template'],correct:1,explanation:'AWS SAM is a CloudFormation extension with shorthand resources (AWS::Serverless::Function, AWS::Serverless::Api) that transform to standard CloudFormation during deployment.'},
{id:'dva34',exams:['dva'],domain:'Development with AWS Services',text:'What is Lambda destination vs DLQ?',options:['They are identical','Destinations (for async invocations) can route to SQS, SNS, Lambda, or EventBridge on success OR failure with full event payload; DLQ only handles failures and sends to SQS/SNS','DLQ is newer than destinations','Destinations are for synchronous; DLQ is for async invocations'],correct:1,explanation:'Destinations are more flexible than DLQ—they handle both success and failure for async invocations and include the full event, function response, and context.'},
{id:'dva35',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is CloudWatch Application Insights?',options:['Insights into the CloudWatch application itself','An automated service that detects and diagnoses anomalies in .NET and SQL Server applications deployed on AWS','A custom metrics service','An application performance monitoring pricing tier'],correct:1,explanation:'CloudWatch Application Insights automatically sets up key metrics, logs, and alarms for .NET and SQL Server applications, identifying symptoms of problems.'},
{id:'dva36',exams:['dva'],domain:'Development with AWS Services',text:'What is DynamoDB Local Secondary Index (LSI)?',options:['A locally cached index','An index with the same partition key as the base table but a different sort key, created at table creation time only','A local backup index','A lower-cost alternative to GSI'],correct:1,explanation:'LSIs share the partition key with the base table but use a different sort key. They must be defined at table creation and support strong consistency reads.'},
{id:'dva37',exams:['dva'],domain:'Security',text:'What is AWS Secrets Manager rotation?',options:['Physically rotating server disks','Automatically updating secrets (like database passwords) on a defined schedule, updating the secret value and updating dependent applications','Rotating IAM access keys','Rotating S3 encryption keys'],correct:1,explanation:'Secrets Manager rotation uses Lambda functions to automatically rotate secrets on a schedule, updating both the secret value and the resource (e.g., DB password).'},
{id:'dva38',exams:['dva'],domain:'Deployment',text:'What is a Lambda alias?',options:['A nickname for a Lambda function','A pointer to a specific Lambda function version, enabling traffic shifting between versions and stable references for deployed code','An alias in IAM for Lambda','A Lambda deployment stage name'],correct:1,explanation:'A Lambda alias is a named pointer to a specific version, enabling blue/green deployments and canary releases using weighted alias routing between versions.'},
{id:'dva39',exams:['dva'],domain:'Development with AWS Services',text:'How do you implement pagination in DynamoDB?',options:['Using LIMIT and OFFSET like SQL','Using LastEvaluatedKey from query responses as the ExclusiveStartKey in the next request to paginate through results','DynamoDB automatically returns all results','Using page numbers in the request'],correct:1,explanation:'DynamoDB returns a LastEvaluatedKey if results are paginated. Use it as ExclusiveStartKey in the next request to get the next page of results.'},
{id:'dva40',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is the difference between CloudWatch Logs Insights and Metric Filters?',options:['They are the same thing','Logs Insights runs ad-hoc SQL-like queries across log groups for analysis; Metric Filters continuously extract metrics from logs for alarms','Metric Filters can query log history; Insights is for real-time only','Logs Insights is for infrastructure; Metric Filters are for applications'],correct:1,explanation:'Logs Insights is an interactive query tool for ad-hoc log analysis. Metric Filters run continuously to extract metrics from logs for CloudWatch alarms.'},
{id:'dva41',exams:['dva'],domain:'Development with AWS Services',text:'What is API Gateway WebSocket API?',options:['A WebSocket management tool','A two-way communication channel between clients and your backend, maintaining a persistent connection for real-time applications like chat and gaming','A web scraping API','A static website hosting API'],correct:1,explanation:'WebSocket APIs maintain persistent connections, allowing servers to push data to clients in real-time without clients polling, ideal for chat, live feeds, and gaming.'},
{id:'dva42',exams:['dva'],domain:'Security',text:'What is Lambda Execution Role?',options:['A role defining what code can run in Lambda','An IAM role that Lambda assumes to execute your function, granting permissions to call AWS services like S3, DynamoDB, and CloudWatch Logs','A role for Lambda administrators','An execution environment for containers'],correct:1,explanation:'The Lambda Execution Role grants the function permissions to interact with other AWS services. Basic permissions include CloudWatch Logs write access.'},
{id:'dva43',exams:['dva'],domain:'Deployment',text:'What is canary deployment in CodeDeploy for Lambda?',options:['Deploying Lambda to rural areas','Shifting a small percentage of production traffic to the new Lambda version first, monitoring for errors before completing the rollout','A yellow-colored deployment visualization','Deploying without any testing'],correct:1,explanation:'Canary deployments shift a configured percentage (e.g., 10%) to the new version, wait a period, then shift the remaining 90%—with automatic rollback on alarms.'},
{id:'dva44',exams:['dva'],domain:'Development with AWS Services',text:'What is the purpose of SQS Long Polling?',options:['Polling for a long time regardless of results','Waits up to 20 seconds for messages to arrive, reducing empty responses and API costs compared to short polling','A feature for priority messages','A batch receive operation'],correct:1,explanation:'Long polling (ReceiveMessage with WaitTimeSeconds=20) reduces empty ReceiveMessage responses and lowers SQS costs by eliminating unnecessary API calls.'},
{id:'dva45',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is a CloudWatch Alarm state?',options:['A physical alarm in the data center','Alarms have three states: OK (within threshold), ALARM (breach threshold), INSUFFICIENT_DATA (not enough data to determine)','Alarms only have two states: on and off','Alarms have five severity states'],correct:1,explanation:'CloudWatch alarms have three states: OK, ALARM, and INSUFFICIENT_DATA. Transitions between states can trigger actions like SNS notifications or Auto Scaling.'},
{id:'dva46',exams:['dva'],domain:'Development with AWS Services',text:'What is DynamoDB Streams and how does it differ from Kinesis Data Streams?',options:['They are identical','DynamoDB Streams captures item-level changes in a DynamoDB table (24-hr retention); Kinesis Data Streams captures arbitrary data (7-day retention, configurable)','Kinesis is for DynamoDB data only','DynamoDB Streams has longer retention'],correct:1,explanation:'DynamoDB Streams captures DB change events (24-hr retention). Kinesis is a general-purpose stream with longer retention and more consumers, better for complex event processing.'},
{id:'dva47',exams:['dva'],domain:'Security',text:'What is AWS WAF rate-based rule?',options:['A pricing rule for WAF usage','Automatically blocks or counts requests from a specific IP that exceed a defined rate (requests per 5 minutes) to protect against DDoS and brute force','A rule for rating web applications','A performance-based routing rule'],correct:1,explanation:'Rate-based rules in WAF track request rates per IP and automatically block those exceeding the threshold (minimum 100 req/5min), protecting against volumetric attacks.'},
{id:'dva48',exams:['dva'],domain:'Deployment',text:'What is CDK (Cloud Development Kit)?',options:['A CD-ROM development kit','An open-source framework for defining cloud infrastructure as code using familiar programming languages (Python, TypeScript, Java, C#) that synthesize to CloudFormation','A continuous deployment kit','A cloud database kit'],correct:1,explanation:'AWS CDK allows defining infrastructure using programming languages with object-oriented constructs, generating CloudFormation templates with higher-level abstractions.'},
{id:'dva49',exams:['dva'],domain:'Development with AWS Services',text:'What is S3 presigned URL and when would you use it?',options:['A URL that expires after use','A time-limited URL that grants temporary access to a private S3 object for upload or download without requiring AWS credentials','A URL that always works','A permanent public URL for S3 objects'],correct:1,explanation:'Presigned URLs grant temporary, expiring access to private S3 objects. Use them to allow users to directly upload/download S3 objects without AWS credentials.'},
{id:'dva50',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is AWS Lambda Power Tuning?',options:['A way to overclock Lambda functions','An open-source tool that runs your Lambda at different memory settings to find the optimal balance between cost and performance','A power management feature for Lambda','A Lambda billing optimization calculator'],correct:1,explanation:'Lambda Power Tuning (AWS Step Functions state machine) runs your function with different memory configurations and identifies the best cost-performance balance.'},
{id:'dva51',exams:['dva'],domain:'Development with AWS Services',text:'What is API Gateway Integration Type AWS_PROXY?',options:['A proxy for multiple API Gateways','Lambda proxy integration that passes the entire request to Lambda and expects the function to return a properly formatted response object','A proxy for AWS internal APIs','An API that proxies to other AWS services directly'],correct:1,explanation:'Lambda Proxy integration passes the full HTTP request (headers, path, body, query strings) as a JSON event to Lambda, and expects a specific response structure back.'},
{id:'dva52',exams:['dva'],domain:'Security',text:'What is Resource-Based Policy in AWS Lambda?',options:['A policy based on computing resources','A policy attached directly to a Lambda function that controls which services, accounts, or IAM principals can invoke the function','A RAM allocation policy','A resource limit policy'],correct:1,explanation:'Lambda resource-based policies grant other services (S3, API Gateway, SNS) or accounts permission to invoke the function without modifying the caller\'s IAM policies.'},
{id:'dva53',exams:['dva'],domain:'Deployment',text:'What is an Elastic Beanstalk environment tier?',options:['A pricing tier for Elastic Beanstalk','Web Server tier (handles HTTP/HTTPS requests with ALB) vs Worker tier (processes background jobs from SQS queue)','A geographic tier for Elastic Beanstalk deployments','A performance tier configuration'],correct:1,explanation:'Web Server tier uses ELB to handle HTTP traffic. Worker tier pulls tasks from an SQS queue using an SQS daemon, ideal for background processing.'},
{id:'dva54',exams:['dva'],domain:'Development with AWS Services',text:'What is the purpose of EventBridge Schema Registry?',options:['A registry for event venue bookings','Automatically discovers event schemas from your bus and generates code bindings in multiple languages for strongly-typed event handling','A JSON schema validation tool','A registry for EventBridge rules'],correct:1,explanation:'Schema Registry discovers and stores event schemas from your event bus, enabling code generation in Python, Java, and TypeScript for type-safe event handling.'},
{id:'dva55',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'How do you debug a Lambda function that times out?',options:['Increase timeout indefinitely','Use X-Ray to identify which subsegment is taking longest, check CloudWatch Logs for execution duration, and review external calls (DB, HTTP, S3)','Just increase memory','Disable all external calls'],correct:1,explanation:'X-Ray traces show timing for each subsegment. CloudWatch Logs show duration. Common causes: slow DB queries, unoptimized code, cold starts, or overly complex logic.'},
{id:'dva56',exams:['dva'],domain:'Development with AWS Services',text:'What is DynamoDB PartiQL?',options:['A partial SQL implementation for DynamoDB','A SQL-compatible query language for DynamoDB that lets you run SQL-like SELECT, INSERT, UPDATE, DELETE statements while using DynamoDB under the hood','A parallel query language','A partitioned SQL database'],correct:1,explanation:'DynamoDB PartiQL provides a SQL-compatible interface for DynamoDB, letting developers use familiar SQL syntax without changing the underlying DynamoDB data model.'},
{id:'dva57',exams:['dva'],domain:'Security',text:'What is S3 Block Public Access?',options:['A firewall blocking S3 from the internet','Account or bucket-level settings that override any policies that would grant public access, preventing accidental public exposure of data','Blocking specific S3 API operations','A VPC endpoint restriction'],correct:1,explanation:'S3 Block Public Access settings override bucket policies and ACLs that would make objects public, providing a fail-safe against accidental data exposure.'},
{id:'dva58',exams:['dva'],domain:'Deployment',text:'What is AWS CloudFormation Rollback?',options:['A physical server rollback mechanism','Automatically reverts a stack to the previous state when a create or update fails, undoing all changes made during the failed operation','A manual process for reverting stacks','A partial rollback of only failed resources'],correct:1,explanation:'CloudFormation automatically rolls back all changes on failure, returning the stack to the last known good state, unless disable rollback is configured.'},
{id:'dva59',exams:['dva'],domain:'Development with AWS Services',text:'What is Lambda Cold Start and how can you mitigate it?',options:['Lambda running in cold environments','The initialization delay when Lambda starts a new execution environment; mitigated by Provisioned Concurrency, keeping functions warm, and optimizing package size','A Lambda debugging state','Lambda running on cheaper hardware'],correct:1,explanation:'Cold starts occur when Lambda must initialize a new execution environment. Mitigations: Provisioned Concurrency, smaller packages, efficient initialization code.'},
{id:'dva60',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is the CloudWatch ServiceLens?',options:['A physical camera for monitoring servers','Unifies CloudWatch Metrics, Logs, and X-Ray Traces in one view, providing an end-to-end picture of application health and performance','A lens for CloudWatch dashboards','A monitoring service for optical networks'],correct:1,explanation:'ServiceLens integrates CloudWatch and X-Ray to provide a unified view of application health, showing how metrics, logs, and traces are correlated.'},
{id:'dva61',exams:['dva'],domain:'Development with AWS Services',text:'What is the maximum size of a Lambda deployment package (zipped)?',options:['5 MB','50 MB','250 MB unzipped','500 MB'],correct:1,explanation:'Lambda deployment package limits: 50 MB zipped (direct upload), 250 MB unzipped. Use S3 for packages > 50 MB, or Lambda Layers to share large dependencies.'},
{id:'dva62',exams:['dva'],domain:'Security',text:'What is Cognito Token Validation?',options:['Counting the number of Cognito tokens','Verifying the signature, expiration, and claims of a JWT token issued by Cognito using the public key from the JWKS endpoint','A billing validation for Cognito usage','Validating Cognito user emails'],correct:1,explanation:'Validate Cognito tokens by: 1) Verify signature using Cognito\'s JWKS public keys, 2) Check expiration (exp), 3) Validate audience (aud) and issuer (iss) claims.'},
{id:'dva63',exams:['dva'],domain:'Deployment',text:'What is a Lambda version?',options:['The Lambda runtime version','An immutable snapshot of a Lambda function including code and configuration, identified by a version number, ARN, and cannot be changed after publishing','The Lambda SDK version','A Lambda pricing version'],correct:1,explanation:'Publishing a Lambda version creates an immutable snapshot. Versions have unique ARNs. Use aliases to point to versions and enable traffic shifting.'},
{id:'dva64',exams:['dva'],domain:'Development with AWS Services',text:'What is Amazon API Gateway usage plan?',options:['A billing plan for API Gateway','Defines throttling (rate limit, burst) and quota (max requests per period) for API keys, controlling access to your API by API consumers','A feature usage tracking plan','A developer onboarding plan'],correct:1,explanation:'Usage plans set throttle (rate, burst) and quota limits on API keys, allowing you to offer different API tiers to customers.'},
{id:'dva65',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is a CloudFormation Stack Drift?',options:['Stack performance degradation over time','When the actual state of stack resources differs from the expected state defined in the CloudFormation template due to manual changes','Stack migration across regions','A CloudFormation pricing fluctuation'],correct:1,explanation:'Drift detection identifies configuration differences between the current live state of stack resources and the CloudFormation template definition.'},
{id:'dva66',exams:['dva'],domain:'Development with AWS Services',text:'What is the AWS Amplify?',options:['A signal amplification service','A set of tools and services for building full-stack web and mobile apps with backend features like auth, storage, APIs, and hosting','An EC2 performance amplification tool','A Lambda memory amplification feature'],correct:1,explanation:'AWS Amplify provides a CLI, libraries, and hosting for building full-stack apps with pre-built authentication, GraphQL/REST APIs, storage, and CI/CD.'},
{id:'dva67',exams:['dva'],domain:'Security',text:'What is the purpose of STS AssumeRole?',options:['Taking over an AWS account','Allows principals (users, services, accounts) to obtain temporary security credentials for a specified role, enabling cross-account access and role chaining','A static role assumption','Permanent role switching'],correct:1,explanation:'STS AssumeRole returns temporary credentials (access key, secret, session token) for an IAM role, enabling cross-account access and temporary privilege elevation.'},
{id:'dva68',exams:['dva'],domain:'Deployment',text:'What are CodePipeline Actions?',options:['Physical actions performed by engineers','The individual tasks within a pipeline stage (source, build, test, deploy, invoke, approval) that CodePipeline executes','A set of CodePipeline CLI commands','GitHub actions integrated with CodePipeline'],correct:1,explanation:'Actions are the work units within stages. Types include Source (get code), Build (compile), Test (run tests), Deploy (deploy artifact), and Approval (manual gate).'},
{id:'dva69',exams:['dva'],domain:'Development with AWS Services',text:'How does Lambda handle concurrent executions?',options:['Lambda processes requests sequentially','Each concurrent request gets its own execution environment (cold or warm); account-level concurrency limit is 1000 by default, adjustable per function','Lambda queues all requests','Lambda reuses the same container for all concurrent requests'],correct:1,explanation:'Lambda scales by creating new execution environments per concurrent request up to the account limit (1000 default). Reserved concurrency sets per-function limits.'},
{id:'dva70',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is AWS Distro for OpenTelemetry (ADOT)?',options:['An open-source AWS data transfer tool','A distribution of OpenTelemetry APIs and SDKs for collecting distributed traces and metrics that integrates with X-Ray, CloudWatch, and other backends','A network telemetry service','An open-source cloud monitoring framework'],correct:1,explanation:'ADOT is an AWS-supported OpenTelemetry distribution that lets you collect traces/metrics from your apps and send them to X-Ray, CloudWatch, and other observability backends.'},
{id:'dva71',exams:['dva'],domain:'Development with AWS Services',text:'What is the benefit of using AWS SDK v3 over v2?',options:['v3 is completely incompatible with AWS services','v3 uses modular packages (import only what you need), TypeScript-first design, and improved middleware stack, resulting in smaller bundle sizes','v3 is only for JavaScript','v2 has better performance than v3'],correct:1,explanation:'AWS SDK v3 is modular (tree-shakeable), TypeScript-first, and has a middleware stack for customization. Smaller bundles are critical for Lambda cold starts.'},
{id:'dva72',exams:['dva'],domain:'Security',text:'What is S3 CORS configuration used for?',options:['Cross-Origin Ransomware Security','Allowing web applications hosted on one domain to make requests to an S3 bucket from a different domain in a browser','Cross-region object replication security','A security rule for S3 Cross-AZ access'],correct:1,explanation:'S3 CORS configuration allows web browsers to make cross-origin requests to your S3 bucket, needed when hosting frontend assets that call S3 APIs directly.'},
{id:'dva73',exams:['dva'],domain:'Deployment',text:'What is AWS CodeStar?',options:['A star rating system for AWS services','A service that provides a unified interface for developing, building, and deploying applications on AWS, integrating CodeCommit, CodeBuild, CodeDeploy, and CodePipeline','A star topology networking service','An AWS partner certification'],correct:1,explanation:'AWS CodeStar provides a unified UI to manage software development activities including source control, build, deploy, and monitoring—all pre-wired together.'},
{id:'dva74',exams:['dva'],domain:'Development with AWS Services',text:'What is SQS message attribute?',options:['An attribute describing SQS pricing','Metadata attached to an SQS message (up to 10 name-type-value attributes) that provides structured information about the message without changing the body','A message priority attribute','An attribute for message routing'],correct:1,explanation:'Message attributes allow attaching metadata to messages (e.g., contentType, sourceSystem) that consumers can use for filtering or processing decisions without parsing the body.'},
{id:'dva75',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is the CloudWatch GetMetricStatistics API?',options:['A statistical analysis tool','Retrieves statistics (Average, Sum, Maximum, Minimum, SampleCount) for a specified metric over a time period','An API for statistical computing','A real-time metrics API'],correct:1,explanation:'GetMetricStatistics retrieves CloudWatch metric data points for a time range with statistics like Average, Sum, Min, Max—useful for custom dashboards.'},
{id:'dva76',exams:['dva'],domain:'Development with AWS Services',text:'What is AWS AppConfig?',options:['An app store configuration tool','A service for creating, managing, and deploying application configuration—separate from code—with validation, monitored rollouts, and instant rollback','A mobile app configuration panel','A CloudFormation configuration service'],correct:1,explanation:'AppConfig separates configuration from code, enabling safe, validated configuration changes with gradual rollouts and automatic rollback on alarms.'},
{id:'dva77',exams:['dva'],domain:'Security',text:'What is mutual TLS (mTLS) in API Gateway?',options:['Multiple TLS certificates for one API','Two-way certificate-based authentication where both the API Gateway and client present certificates to verify each other','TLS for multi-region APIs','A deprecated SSL protocol'],correct:1,explanation:'mTLS requires clients to present X.509 certificates, and API Gateway validates them against a truststore, providing strong client authentication for B2B APIs.'},
{id:'dva78',exams:['dva'],domain:'Deployment',text:'What is a Lambda function URL?',options:['The URL of the Lambda console','A built-in HTTPS endpoint for a Lambda function without needing API Gateway, supporting auth via AWS IAM or none (public)','A URL shortening service built on Lambda','The endpoint for Lambda VPC access'],correct:1,explanation:'Function URLs give Lambda functions a dedicated HTTPS endpoint directly (no API Gateway needed), with optional IAM_AUTH or NONE authentication.'},
{id:'dva79',exams:['dva'],domain:'Development with AWS Services',text:'What is the purpose of DynamoDB Scan vs Query?',options:['They are identical','Query efficiently retrieves items using the primary key (or GSI); Scan reads every item in the table, which is slow and expensive for large tables','Scan is faster than Query','Query reads every item; Scan uses indexes'],correct:1,explanation:'Query uses key conditions to fetch specific items efficiently. Scan reads all items (full table scan)—use Query when possible and avoid Scan on large tables.'},
{id:'dva80',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is CloudWatch Synthetics?',options:['A synthetic data generation tool','Creates configurable canary scripts that run scheduled checks on your endpoints and APIs to detect issues before customers notice','A monitoring service for chemical plants','A fake data generator for testing'],correct:1,explanation:'CloudWatch Synthetics canaries are configurable scripts that run on a schedule to check endpoint/API availability and latency, alerting you before users report issues.'},
{id:'dva81',exams:['dva'],domain:'Development with AWS Services',text:'What is AWS Step Functions Express Workflow vs Standard Workflow?',options:['Express is newer; Standard is legacy','Express: high-volume, short duration (< 5 min), at-least-once execution, lower cost; Standard: long duration (1 year), exactly-once execution, higher cost','Express runs only one step; Standard runs many','Standard has limited integrations; Express has full integrations'],correct:1,explanation:'Standard workflows guarantee exactly-once execution, support up to 1 year duration, and have full audit history. Express workflows are cheaper for high-volume, short, at-least-once tasks.'},
{id:'dva82',exams:['dva'],domain:'Security',text:'What is IAM Access Analyzer?',options:['A tool for analyzing IAM policy complexity','Analyzes resource-based policies to identify resources accessible from outside your account or organization, helping prevent unintended public access','A cost analyzer for IAM users','An IAM performance analyzer'],correct:1,explanation:'IAM Access Analyzer identifies resources (S3 buckets, Lambda functions, KMS keys, IAM roles) shared with external entities, helping detect unintended public exposure.'},
{id:'dva83',exams:['dva'],domain:'Deployment',text:'What is the purpose of AWS Systems Manager Run Command?',options:['Running commands on the AWS console','Remotely and securely executes commands on EC2 instances or on-premises machines without SSH/RDP access','A command scheduler','A Lambda invocation service'],correct:1,explanation:'Run Command lets you manage instances at scale by executing scripts remotely via the SSM Agent, without opening inbound ports or using bastion hosts.'},
{id:'dva84',exams:['dva'],domain:'Development with AWS Services',text:'What is SNS message filtering?',options:['Blocking inappropriate SNS messages','Subscription filter policies that define which messages a subscriber receives based on message attributes, reducing unnecessary processing','A content moderation feature','Filtering SNS topics by size'],correct:1,explanation:'Filter policies on SQS subscriptions to SNS topics let each subscriber receive only the messages matching their attribute criteria, reducing SQS processing costs.'},
{id:'dva85',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'How do you detect Lambda throttling?',options:['Lambda sends an email alert','Monitor the Throttles CloudWatch metric for the function and set an alarm; throttled invocations return 429 errors to callers','Check EC2 console for throttling','Use CloudTrail to detect throttling'],correct:1,explanation:'The Lambda Throttles metric shows the number of throttled invocations. Set a CloudWatch alarm on this metric, and consider requesting a concurrency limit increase.'},
{id:'dva86',exams:['dva'],domain:'Development with AWS Services',text:'What is AWS Pinpoint for developers?',options:['A GPS tracking service','A service for sending targeted push notifications, emails, SMS, and voice messages with analytics tracking delivery and engagement','A pin-based authentication system','A developer marketplace'],correct:1,explanation:'Pinpoint enables sending targeted multi-channel communications with tracking of deliverability, opens, clicks, and conversions for user engagement analytics.'},
{id:'dva87',exams:['dva'],domain:'Security',text:'What is envelope encryption in AWS?',options:['Encrypting envelopes for mail delivery','Using a data key to encrypt data and then encrypting the data key with a master key (CMK) in KMS, limiting the amount of data processed by KMS','A two-layer envelope pattern','Encrypting data in transit and at rest simultaneously'],correct:1,explanation:'Envelope encryption: generate a data key (via KMS), encrypt data with the data key locally, then encrypt the data key with your CMK. Only encrypted data key is stored with data.'},
{id:'dva88',exams:['dva'],domain:'Deployment',text:'What is EC2 Image Builder?',options:['An image editing service for EC2 dashboards','A fully managed service to automate the creation, management, and deployment of customized, secure, and up-to-date server images (AMIs)','A tool for building container images only','An image CDN for EC2 applications'],correct:1,explanation:'EC2 Image Builder automates the creation and testing of AMIs—defining a pipeline of components (scripts, validations) to build patched, compliant images.'},
{id:'dva89',exams:['dva'],domain:'Development with AWS Services',text:'What is AWS App Runner?',options:['A marathon event management service','A fully managed service for deploying containerized web applications and APIs directly from source code or container images with automatic scaling','A script runner for EC2','An App Store submission tool'],correct:1,explanation:'App Runner builds, deploys, and scales containerized web apps automatically—no infrastructure management needed. Deploy from GitHub or ECR with automatic scaling.'},
{id:'dva90',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is the difference between CloudWatch Metrics and CloudWatch Logs?',options:['Metrics are for databases; Logs are for applications','Metrics are numerical time-series data points for alarms and dashboards; Logs are text-based records of events for querying and debugging','Logs are structured; Metrics are unstructured','They are identical and interchangeable'],correct:1,explanation:'Metrics are numerical data points (CPU usage, request count) with timestamps for alarming/graphing. Logs are text records of events for debugging and analysis.'},
{id:'dva91',exams:['dva'],domain:'Development with AWS Services',text:'What is the AWS SDK Waiter?',options:['A queue waiting mechanism','A helper that polls AWS APIs until a resource reaches a desired state (e.g., EC2 instance running, S3 object exists) with built-in retry logic','A Lambda concurrency waiting feature','An API rate limiter'],correct:1,explanation:'Waiters poll APIs at intervals until the desired state is achieved (or timeout), abstracting the polling logic so you do not need to write retry/polling code.'},
{id:'dva92',exams:['dva'],domain:'Security',text:'What is AWS GuardDuty finding and how should a developer respond?',options:['A lost item report','GuardDuty findings indicate potential threats (compromised credentials, unusual API calls, crypto mining); developers should use EventBridge to automate responses via Lambda','A GuardDuty user interface finding','A performance finding in the code'],correct:1,explanation:'GuardDuty findings (e.g., UnauthorizedAccess, CryptoCurrency:EC2) should trigger automated remediation via EventBridge→Lambda: isolate instances, rotate credentials, notify teams.'},
{id:'dva93',exams:['dva'],domain:'Deployment',text:'What is an AWS CloudFormation StackSet?',options:['A set of CloudFormation documentation stacks','Extends stacks to deploy across multiple accounts and regions with a single operation, managed centrally via an administrator account','A collection of Lambda deployment stacks','A testing stack collection'],correct:1,explanation:'StackSets enable centralized management of stacks across multiple accounts and regions, useful for deploying baseline configurations organization-wide.'},
{id:'dva94',exams:['dva'],domain:'Development with AWS Services',text:'What is the purpose of DynamoDB On-Demand vs Provisioned throughput?',options:['They are priced identically','On-Demand scales automatically and charges per request (higher per-request cost, no planning); Provisioned requires capacity planning but is cheaper for predictable workloads','On-Demand is always cheaper','Provisioned has no limits'],correct:1,explanation:'On-Demand is serverless capacity—pay per request, scales instantly. Provisioned requires specifying RCU/WCU, is cheaper for consistent traffic, with Auto Scaling available.'},
{id:'dva95',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'What is AWS CloudTrail Lake?',options:['A data lake for physical infrastructure logs','A managed data lake for querying CloudTrail events with SQL, retaining audit logs for up to 7 years','A lake formation integration for CloudTrail','A cool-temperature storage tier for audit logs'],correct:1,explanation:'CloudTrail Lake stores and manages CloudTrail events as an immutable data lake, with SQL-based event querying and up to 7-year retention for compliance.'},
{id:'dva96',exams:['dva'],domain:'Development with AWS Services',text:'What is Amazon Bedrock?',options:['A bedrock geological survey service','A fully managed service for accessing foundation models (FMs) from leading AI companies via an API to build generative AI applications','A physical foundation layer for AWS data centers','A low-level networking service'],correct:1,explanation:'Amazon Bedrock provides access to foundation models from Anthropic, Meta, Mistral, and Amazon via API, enabling developers to build generative AI apps without managing ML infrastructure.'},
{id:'dva97',exams:['dva'],domain:'Security',text:'What is S3 Bucket Versioning and how does it protect data?',options:['Tracking S3 bucket software versions','Preserving, retrieving, and restoring every version of every object stored in S3, protecting against accidental deletions and overwrites','A version control system for S3 configuration','S3 API version management'],correct:1,explanation:'Versioning keeps multiple versions of each object. A delete creates a delete marker (recoverable); overwrites preserve old versions—protecting against accidental data loss.'},
{id:'dva98',exams:['dva'],domain:'Deployment',text:'What is AWS Proton?',options:['A proton beam accelerator service','A fully managed service for deploying and managing container and serverless application infrastructure using consistent, approved infrastructure templates','A chemical element management service','A networking protocol service'],correct:1,explanation:'AWS Proton lets platform teams define and vend approved infrastructure templates for developers, ensuring consistent, compliant infrastructure across microservices.'},
{id:'dva99',exams:['dva'],domain:'Development with AWS Services',text:'What is Amazon EventBridge Pipes?',options:['A plumbing service for data centers','A feature for creating point-to-point integrations between event producers and consumers with built-in filtering, enrichment, and transformation','A pipe for streaming videos','An EventBridge pricing model'],correct:1,explanation:'EventBridge Pipes connect sources (SQS, DynamoDB Streams, Kinesis) to targets (Lambda, Step Functions, SQS) with filtering and enrichment—reducing event-driven boilerplate code.'},
{id:'dva100',exams:['dva'],domain:'Monitoring & Troubleshooting',text:'How do you implement structured logging for Lambda functions for better CloudWatch Logs querying?',options:['Use print statements only','Emit JSON-formatted log lines with consistent keys (requestId, userId, level, message), enabling efficient Logs Insights queries','Use unstructured text for flexibility','Disable logging for performance'],correct:1,explanation:'Structured (JSON) logging with consistent keys (level, requestId, duration) makes CloudWatch Logs Insights queries fast and reliable for debugging and metrics extraction.'},
];
